    32→    s_asset1Report.dataStreamsFeedId = i_asset1dataStreamsFeedId;
    33→    s_asset1Report.price = int192(uint192(ASSET_1_PRICE));
    34→    s_asset1Report.observationsTimestamp = uint32(block.timestamp);
    35→
    36→    s_asset2Report.dataStreamsFeedId = i_asset2dataStreamsFeedId;
    37→    s_asset2Report.price = int192(uint192(ASSET_2_PRICE));
    38→    s_asset2Report.observationsTimestamp = uint32(block.timestamp);
