    65→
    66→  function test_transmit_RevertWhen_CallerDoesNotHavePRICE_ADMIN_ROLE()
    67→    external
    68→    whenCallerIsNotPriceAdmin
    69→    performForAllContracts(CommonContracts.PRICE_MANAGER)
    70→  {
    71→    vm.expectRevert(
    72→      abi.encodeWithSelector(IAccessControl.AccessControlUnauthorizedAccount.selector, i_owner, Roles.PRICE_ADMIN_ROLE)
    73→    );
    74→    PriceManager(s_contractUnderTest).transmit(s_unverifiedReports);
    75→  }
    76→
    77→  function test_transmit_RevertWhen_EmptyReportList() external performForAllContracts(CommonContracts.PRICE_MANAGER) {
    78→    vm.expectRevert(Errors.EmptyList.selector);
    79→
    80→    PriceManager(s_contractUnderTest).transmit(new bytes[](0));
    81→  }
    82→
    83→  function test_transmit_RevertWhen_FeedIsNotAllowlisted()
    84→    external
    85→    performForAllContracts(CommonContracts.PRICE_MANAGER)
    86→  {
    87→    PriceManager.ReportV3 memory invalidReportData = s_asset1Report;
    88→    invalidReportData.dataStreamsFeedId =
    89→      bytes32(bytes.concat(bytes2(0x0003), bytes30(keccak256("invaliddataStreamsFeedId"))));
    90→    invalidReportData.price = int192(uint192(ASSET_1_PRICE));
    91→    invalidReportData.observationsTimestamp = uint32(block.timestamp);
    92→
